/// Positive controls: every `tcps:RangeGuardPassCase` individual must make
/// the REAL `範囲防止::検査する` return `成否::成功`. If this fails, the
/// guard is rejecting legitimate input -- fails open in the wrong direction
/// (over-eager refusal). cap06's capDesc requires proving the pack "fails
/// closed, not just that it succeeds", which cuts both ways: a guard that
/// rejects everything trivially "fails closed" but is useless, so a
/// positive control is required here, not optional.
#[test]
fn range_guard_accepts_every_declared_pass_case() {
    for case in RANGE_PASS_CASES {
        let guard = 範囲防止 {
            最小: case.min,
            最大: case.max,
            理由番号: case.reason_code,
        };
        let result = guard.検査する(&case.input);
        assert!(
            matches!(result, 成否::成功(_)),
            "case `{}`: input {} declared in ontology.ttl as tcps:RangeGuardPassCase for range \
             [{}, {}] was rejected by the real 範囲防止::検査する -- guard is over-eager, not \
             fail-closed correctly",
            case.name,
            case.input,
            case.min,
            case.max
        );
    }
}

